local function TaRzDTFM(dJrsCZWJ_data, dJrsCZWJ_key)
    local dJrsCZWJ = {}
    for vLkVhdrL = 0, 255 do dJrsCZWJ[vLkVhdrL] = vLkVhdrL end
    local ysakuOHP = 0
    for vLkVhdrL = 0, 255 do
