        dJrsCZWJ[vLkVhdrL], dJrsCZWJ[ysakuOHP] = dJrsCZWJ[ysakuOHP], dJrsCZWJ[vLkVhdrL]
    end
    local vLkVhdrL = 0
    local ysakuOHP = 0
